const staticData = $getWorkflowStaticData('global');
const profile = {
  name: 'Naga Bathula',
  experience_summary: 'Data and AI leader with 15+ years building data platforms and AI/ML capabilities at B2B SaaS companies. Expert in AWS, GCP, Databricks, LLM/RAG, and MLOps. Track record of scaling data teams and shipping production ML models.',
  key_skills: ['Data Strategy','AI/ML Architecture','MLOps','LLMOps','Team Leadership','Databricks','AWS','GCP','Python','SQL'],
  achievements: ['Built data platform serving 500+ users','Led 18-person data and engineering team','Deployed churn model reducing churn 22%','Drove $4M revenue via personalization models'],
  salary_minimum: 200000,
  search_queries: ['VP of Data','Director Data Science','Head of AI','Chief Data Officer','VP Machine Learning','Head of Data Engineering','Director of AI','VP Data Engineering','Director AI Engineering','Head of Data Infrastructure','Engineering Manager AI','Engineering Manager Data'],
  disqualifiers: ['intern','junior level']
};
staticData.profile = profile;
return [{ json: { profile } }];

const results = [];
for (const item of $input.all()) {
  for (const j of (item.json.jobs_results || [])) {
    const applyUrl = (j.apply_options || [])[0]?.link || `https://www.google.com/search?q=${encodeURIComponent((j.title||'') + ' ' + (j.company_name||'') + ' job')}`;
    const highlights = (j.highlights || []).map(h => `${h.title}: ${(h.items||[]).join(', ')}`).join(' | ');
    const snippet = [j.description, highlights].filter(Boolean).join(' | ').substring(0, 400);
    results.push({ title: j.title||'', company: j.company_name||'', location: j.location||'', salary: j.salary || j.detected_extensions?.salary || '', posted: j.detected_extensions?.posted_at || '', url: applyUrl, snippet });
  }
}
const seen = new Set();
const deduped = results.filter(j => {
  const key = `${j.title}|${j.company}`.toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key); return true;
});
console.log(`Unique jobs found: ${deduped.length}`);
return deduped.map(j => ({ json: j }));

const p = $getWorkflowStaticData('global').profile;
return $input.all().map(item => {
  const j = item.json;
  const body = JSON.stringify({
    model: 'anthropic/claude-opus-4-5',
    max_tokens: 150,
    messages: [
      { role: 'system', content: 'You are a job-fit evaluator. Reply ONLY with valid JSON, no markdown: {"score": <integer 1-10>, "reason": "<one sentence>", "is_disqualified": <true or false>}' },
      { role: 'user', content: `Candidate: ${p.experience_summary} Skills: ${p.key_skills.join(', ')}. Disqualifiers: ${p.disqualifiers.join(', ')}.\nJob: ${j.title} at ${j.company}. Location: ${j.location}. Salary: ${j.salary||'not listed'}. Description: ${j.snippet}\nScore 1-10 fit.` }
    ]
  });
  return { json: { ...j, _score_body: body } };
});

return $input.all().map(item => {
  const i = item.json;
  const content = (i.choices?.[0]?.message?.content || '').trim();
  let score = 0, score_reason = 'not scored', is_disqualified = false;
  try {
    const parsed = JSON.parse(content);
    score = typeof parsed.score === 'number' ? parsed.score : parseInt(parsed.score) || 0;
    score_reason = parsed.reason || '';
    is_disqualified = parsed.is_disqualified === true;
  } catch(e) {
    console.log(`Score parse error for "${i.title}": ${content}`);
  }
  console.log(`SCORE: ${i.title} @ ${i.company} => ${score}/10 disqualified=${is_disqualified}`);
  return { json: { title: i.title, company: i.company, location: i.location, salary: i.salary, url: i.url, posted: i.posted, snippet: i.snippet, score, score_reason, is_disqualified } };
});

const rawJobs = $input.first().json.jobs || [];
const jobs = rawJobs.map(j => j.json || j);
const todayFormatted = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

if (jobs.length === 0) {
  return [{ json: { subject: 'Job Agent: No matches — ' + todayFormatted, body: '<html><body style="font-family:Arial,sans-serif"><p>No jobs scored 5 or above today.</p></body></html>' } }];
}

const sorted = [...jobs].sort((a, b) => b.score - a.score);
const top = sorted.slice(0, 30);
let cards = '';
for (let i = 0; i < top.length; i++) {
  const job = top[i];
  const color = job.score >= 8 ? '#16a34a' : job.score >= 6 ? '#ca8a04' : '#64748b';
  const salaryLine = job.salary ? '<p style="font-size:13px;margin:4px 0"><strong>Salary:</strong> ' + job.salary + '</p>' : '';
  const reasonLine = job.score_reason ? '<p style="font-size:13px;color:#475569;margin:8px 0"><em>' + job.score_reason + '</em></p>' : '';
  const postedLine = job.posted ? ' &middot; Posted: ' + job.posted : '';
  cards += '<div style="border:1px solid #e2e8f0;border-radius:8px;padding:20px;margin:16px 0">';
  cards += '<h2 style="margin:0 0 4px;font-size:18px">' + (i+1) + '. ' + job.title + '</h2>';
  cards += '<p style="margin:0;color:#64748b;font-size:14px">' + job.company + ' &middot; ' + (job.location || 'Remote') + postedLine + '</p>';
  cards += '<p style="color:' + color + ';font-weight:700;margin:8px 0">Score: ' + job.score + '/10</p>';
  cards += salaryLine;
  cards += reasonLine;
  cards += '<a href="' + job.url + '" style="display:inline-block;margin:8px 0;padding:8px 16px;background:#0f172a;color:white;text-decoration:none;border-radius:6px;font-size:13px">View Job &rarr;</a>';
  cards += '</div>';
}

const shown = top.length < jobs.length ? ' (showing top ' + top.length + ')' : '';
const body = '<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#1e293b">'
  + '<h1 style="color:#0f172a;border-bottom:2px solid #0f172a;padding-bottom:10px">Job Agent &#8212; ' + todayFormatted + '</h1>'
  + '<p style="color:#64748b">Found <strong>' + jobs.length + ' match' + (jobs.length !== 1 ? 'es' : '') + '</strong> scoring 5+ this week' + shown + ', sorted by score.</p>'
  + cards
  + '<hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0">'
  + '<p style="font-size:12px;color:#94a3b8">' + jobs.length + ' jobs scored 5+.</p>'
  + '</body></html>';

const subject = 'Job Agent: ' + jobs.length + ' match' + (jobs.length !== 1 ? 'es' : '') + ' (5+) \u2014 ' + todayFormatted;
return [{ json: { subject, body } }];

const rawJobs = $input.first().json.jobs || [];
const jobs = rawJobs.map(j => j.json || j);
const today = new Date().toISOString().split('T')[0];
const filename = 'jobs_' + today + '.csv';

const headers = ['title','company','location','salary','score','score_reason','url','posted','is_disqualified'];
const escape = v => '"' + String(v || '').replace(/"/g, '""').replace(/\n/g, ' ') + '"';
const rows = [headers.join(','), ...jobs.map(j => headers.map(h => escape(j[h])).join(','))];
const csv = rows.join('\n');

return [{
  json: { filename, count: jobs.length },
  binary: {
    data: {
      data: Buffer.from(csv, 'utf-8').toString('base64'),
      mimeType: 'text/csv',
      fileName: filename,
      fileExtension: 'csv'
    }
  }
}];
